div.style:
height:100vh;
display:flex;
flex-direction:column;
justify-content:center;
align-items:center;
text-align:center;

t.script:
let scanner;

function onScanSuccess(decodedText) {

    console.log("QR RAW:", decodedText);

    let match = decodedText.match(/asset_code=([^&]+)/);

    if (match && match[1]) {

        let assetCode = match[1].trim();

        scanner.clear();
        document.getElementById("loading").style.display = "block";

        window.location.href =
            "/asset/redirect_by_code?asset_code=" + assetCode;

    } else {

        document.getElementById("error-msg").innerText =
            "Không tìm thấy Asset Code trong QR.";

        console.log("Không parse được asset_code");
    }
}

function onScanFailure(error) {}

window.addEventListener("load", function () {

    scanner = new Html5QrcodeScanner(
        "reader",
        {
            fps: 20,
            qrbox: function(w, h) {
                var s = Math.min(w, h) * 0.85;
                return { width: s, height: s };
            },
            experimentalFeatures: { useBarCodeDetectorIfSupported: true }
        },
        false
    );

    scanner.render(onScanSuccess, onScanFailure);
});
